1	export type Cell = [number, number];
2	
3	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const neighborsOf = ([x, y]: Cell): Cell[] => [
6	  [x - 1, y - 1], [x, y - 1], [x + 1, y - 1],
7	  [x - 1, y    ],              [x + 1, y    ],
8	  [x - 1, y + 1], [x, y + 1], [x + 1, y + 1],
9	];
10	
11	export function nextGeneration(cells: Cell[]): Cell[] {
12	  const aliveKeys = new Set(cells.map(keyOf));
13	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
14	
15	  for (const cell of cells) {
16	    for (const neighbor of neighborsOf(cell)) {
17	      const key = keyOf(neighbor);
18	      const entry = neighborCounts.get(key);
19	      if (entry) entry.count++;
20	      else neighborCounts.set(key, { cell: neighbor, count: 1 });
21	    }
22	  }
23	
24	  const survives = (key: string, count: number): boolean =>
25	    aliveKeys.has(key) ? count === 2 || count === 3 : count === 3;
26	
27	  return [...neighborCounts]
28	    .filter(([key, { count }]) => survives(key, count))
29	    .map(([, { cell }]) => cell);
30	}
