1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation: 0 neighbors)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (underpopulation: 1 neighbor each)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
15	    // Center cell (1,1) has 4 live neighbors and dies
16	    const input: [number, number][] = [
17	      [0, 0], [1, 0], [2, 0],
18	      [0, 1], [1, 1], [2, 1],
19	    ];
20	    const result = nextGeneration(input);
21	    const keys = new Set(result.map(([x, y]) => `${x},${y}`));
22	    expect(keys.has("1,1")).toBe(false);
23	  });
24	  it("should keep a live cell alive with 2 or 3 neighbors (survival)", () => {
25	    // Top row [(0,0),(1,0),(2,0)] + (1,2). Cell (1,1) is dead with 3 neighbors → reproduces.
26	    // Cell (1,0) has neighbors (0,0) and (2,0) = 2 neighbors → survives.
27	    const input: [number, number][] = [[0, 0], [1, 0], [2, 0], [1, 2]];
28	    const result = nextGeneration(input);
29	    const keys = new Set(result.map(([x, y]) => `${x},${y}`));
30	    expect(keys.has("1,0")).toBe(true);
31	  });
32	  it("should bring a dead cell to life with exactly 3 neighbors (reproduction)", () => {
33	    // Dead cell (1,1) has 3 live neighbors: (0,0), (1,0), (0,1) → becomes alive
34	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
35	    const result = nextGeneration(input);
36	    const keys = new Set(result.map(([x, y]) => `${x},${y}`));
37	    expect(keys.has("1,1")).toBe(true);
38	  });
39	  it("should preserve a block pattern (still life)", () => {
40	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
41	    const result = nextGeneration(block);
42	    expect(result).toHaveLength(4);
43	    expect(new Set(result.map(([x, y]) => `${x},${y}`))).toEqual(
44	      new Set(["0,0", "1,0", "0,1", "1,1"])
45	    );
46	  });
47	  it("should oscillate a blinker pattern from vertical to horizontal", () => {
48	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
49	    const result = nextGeneration(vertical);
50	    expect(result).toHaveLength(3);
51	    expect(new Set(result.map(([x, y]) => `${x},${y}`))).toEqual(
52	      new Set(["-1,1", "0,1", "1,1"])
53	    );
54	  });
55	  it("should handle negative coordinates correctly", () => {
56	    // Block pattern at negative coordinates - should be preserved
57	    const block: [number, number][] = [[-5, -5], [-4, -5], [-5, -4], [-4, -4]];
58	    const result = nextGeneration(block);
59	    expect(result).toHaveLength(4);
60	    expect(new Set(result.map(([x, y]) => `${x},${y}`))).toEqual(
61	      new Set(["-5,-5", "-4,-5", "-5,-4", "-4,-4"])
62	    );
63	  });
64	});
